var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"하아… 하아…","JPN":"はあ……はあ……","ENG":"*Huff... Huff...*","TWN":"呼……呼……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"침식체는 줄어드는데… 이 불길한 기운은 좀처럼 가시질 않네요.","JPN":"侵食体は減ってるのに……この不気味さはなかなか消えませんね。","ENG":"The C.O.s are diminishing... but this eerie feeling isn't going away.","TWN":"侵蝕體正在減少……但這種不祥的感覺並沒有消失。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으음, 그러게. 땀을 많이 흘려서 그런가?","JPN":"うーん、そうだね。汗をかきすぎたせいかな？","ENG":"Mmm, you're right. Maybe it's because we're sweating a lot.","TWN":"嗯，確實。是因為流了很多汗嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"야, 한솔아. 나 땀냄새 많이 나냐?","JPN":"ちょっと、イチロウ。私って汗臭い？","ENG":"Hey, Hansol. Do I smell bad?","TWN":"嘿，楊瀚，我身上有汗味嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"우왓?! 그런 말 하면서 들이대지 마요!","JPN":"うわっ！？　ちょっとくっつかないでくださいよ！","ENG":"Whoa! You can't just get close while saying that!","TWN":"哇？！別靠這麼近！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"한솔 경의 말대로군요. 침식체들을 쓰러트려도 침식파장이 줄어드는 느낌이 없습니다.","JPN":"ヤガミ卿の言うとおりです。侵食体を倒しても、侵食波が減る気配がありません。","ENG":"It's as Hansol said. I don't get the feeling that the Corruption ray is diminishing, even though we're defeating the C.O.s.","TWN":"楊瀚說得沒錯。即使擊殺了侵蝕體，侵蝕波也依然不減。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"응? 진짜루?","JPN":"え？　マジ！？","ENG":"Huh? Really?","TWN":"嗯？真的嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그러고보니 하늘도 평소보다 어두운 느낌인데. 기분 탓인가?","JPN":"そういえば、空がいつもより暗いね。気のせいかな？","ENG":"Now that you mention it, the sky looks darker than usual. What do you think?","TWN":"話說天空似乎比往常更暗了，是我看錯了嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"어?","JPN":"あれれ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"여러분! 하늘에서 하얀 눈이 내리기 시작했어요!","JPN":"みなさん！　空から雪が降り始めましたよ！","ENG":"Look! Snow's falling from the sky!","TWN":"各位！開始下雪了！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"하하, 에리어스. 겨울도 아닌데 갑자기 그게 무슨 소리…","JPN":"はは、アリウス。冬でもないのになに言って……","ENG":"Ha ha, Arius. It's not even winter, what do you–","TWN":"哈哈，埃里奧斯。現在又不是冬天，你在說什……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"응? 정말 눈이 오잖아?","JPN":"えっ……？　本当に雪が降ってる。","ENG":"Huh? It's really snowing.","TWN":"咦？真的下雪了？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"와우, 기상조절기가 있는 관리도시에서 갑자기 눈이 내릴 정도면 바깥은 훨씬 춥겠는데?","JPN":"ワオ、気象調節器がある管理都市でいきなり雪が降るくらいなら、外はもっと寒いかも。","ENG":"Wow, if an Administration City with a weather controller is seeing snow, that must mean it's much colder outside.","TWN":"哇，連一個有氣象調節器的管理城市裡也突然下雪，那麼外面一定更加寒冷。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"비행기는 결항일 테니 당분간 고향에는 못 가겠다!","JPN":"飛行機は欠航だから、しばらく地元には帰れないね！","ENG":"Flights are probably canceled, so I guess I'm not going home for a while!","TWN":"我的航班應該已經被取消了，暫時回不了家了！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그 클리포트 게임이 끝나면, 당분간은 평화가 지속될 것이라 기대했습니다만…","JPN":"あのクリフォトゲームが終れば、しばらくは平和になると期待していましたが……","ENG":"I thought there would be peace once the Qliphoth Game had ended...","TWN":"我本以為逆卡巴拉遊戲結束後，會迎來短暫的和平……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그건 그저 제 바람일 뿐이었을지도 모르겠군요.","JPN":"それは、ただ私の望みだったのかもしれません。","ENG":"But maybe that was just wishful thinking.","TWN":"也許這只是我的一廂情願。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"원로원에도 이 사실을 알려야겠습니다.","JPN":"元老院にもこのことを知らせましょう。","ENG":"I should notify the Elders of this.","TWN":"我得讓元老院知道這件事。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};